**The project structure:**
```
game/
├── worlds/
│   ├── village.holo      ← Scene definition
│   └── dungeon.holo      ← Scene definition
├── systems/
│   ├── combat.hsplus     ← Complex logic
│   ├── inventory.hsplus  ← Data management
│   └── dialogue.hsplus   ← State machine
└── main.hsplus           ← Entry point
```

**village.holo - The blueprint:**
```holo
// Defines WHAT exists and WHERE
composition "Village" {

  environment {
    time: "day"
    weather: "sunny"
  }

  spatial_group "Town_Square" {
    object "Blacksmith" using "NPC" {
      position: [10, 0, 5]
      name: "Grimjaw"
      dialogue_tree: "blacksmith_intro"  // Reference to .hsplus
      shop_inventory: ["sword", "shield", "helmet"]
    }

    object "Well" {
      position: [0, 0, 0]
      traits: ["interactive", "water_source"]
    }
  }

  spatial_group "Enemies_Outside" {
    object "Goblin_1" using "Enemy" {
      position: [50, 0, 30]
      level: 3
      ai_behavior: "patrol"  // Implemented in .hsplus
    }
  }

  // Simple flows stay in .holo
  logic {
    on_interact("Well") {
      Player.health += 10
      ui.toast("Refreshed!")
    }

    on_interact("Blacksmith") {
      // Hands off to .hsplus for complex dialogue
      DialogueSystem.start(Blacksmith.dialogue_tree)
    }
  }
}
```

**dialogue.hsplus - The implementation:**
```hsplus
// Complex state machine that .holo references
import { State, Transition } from "@holoscript/std";
import type { NPC, DialogueNode } from "./types";

interface DialogueState {
  currentNode: string;
  history: string[];
  flags: Map<string, boolean>;
}

export system DialogueSystem {
  private state: DialogueState = {
    currentNode: "root",
    history: [],
    flags: new Map()
  };

  private trees: Map<string, DialogueNode[]> = new Map();

  async start(treeId: string): Promise<void> {
    const tree = await this.loadTree(treeId);
    this.state.currentNode = "root";
    this.state.history = [];

    await this.showNode(tree.root);
  }

  private async showNode(node: DialogueNode): Promise<void> {
    // Display the dialogue
    UI.showDialogue({
      speaker: node.speaker,
      text: node.text,
      choices: this.filterChoices(node.choices)
    });

    // Wait for player choice
    const choice = await UI.waitForChoice();

    // Process the choice
    await this.processChoice(choice);
  }

  private filterChoices(choices: Choice[]): Choice[] {
    // Complex logic: filter based on flags, inventory, reputation
    return choices.filter(c => {
      if (c.requires?.flag && !this.state.flags.get(c.requires.flag)) {
        return false;
      }
      if (c.requires?.item && !Player.hasItem(c.requires.item)) {
        return false;
      }
      return true;
    });
  }

  // ... more complex logic
}
```

**combat.hsplus - Heavy math:**
```hsplus
import { Vec3, clamp, lerp } from "@holoscript/std";

export system CombatSystem {
  calculateDamage(attacker: Entity, defender: Entity, weapon: Weapon): number {
    // Complex formula with many factors
    const baseDamage = weapon.damage * attacker.stats.strength;
    const critChance = attacker.stats.luck / 100;
    const isCrit = Math.random() < critChance;
    const critMultiplier = isCrit ? 2.0 : 1.0;

    const defense = defender.stats.defense;
    const armorReduction = 1 - (defense / (defense + 100));

    const elementalBonus = this.getElementalMultiplier(
      weapon.element, 
      defender.resistances
    );

    const finalDamage = Math.floor(
      baseDamage * critMultiplier * armorReduction * elementalBonus
    );

    return clamp(finalDamage, 1, 9999);
  }

  // This would be awful to write in .holo
  getElementalMultiplier(element: Element, resistances: Resistances): number {
    const resist = resistances[element] ?? 0;
    if (resist > 100) return 0;  // Immune
    if (resist > 0) return 1 - (resist / 100);  // Resistant
    if (resist < 0) return 1 + (Math.abs(resist) / 100);  // Weak
    return 1;  // Neutral
  }
}
```

**main.hsplus - Ties it together:**
```hsplus
import { loadWorld } from "@holoscript/core";
import { DialogueSystem } from "./systems/dialogue";
import { CombatSystem } from "./systems/combat";
import { InventorySystem } from "./systems/inventory";

async function main() {
  // Load the .holo scene
  const village = await loadWorld("./worlds/village.holo");

  // Register .hsplus systems
  village.registerSystem(DialogueSystem);
  village.registerSystem(CombatSystem);
  village.registerSystem(InventorySystem);

  // Start the game
  village.start();
}

main();
```

**The relationship:**
```
.holo defines:          .hsplus implements:
─────────────           ────────────────────
"Blacksmith NPC"   →    DialogueSystem handles talking
"Goblin enemy"     →    CombatSystem handles fighting
"Shop inventory"   →    InventorySystem handles items

.holo = WHAT            .hsplus = HOW
```

They're partners - .holo describes the world, .hsplus brings it to life!

Absolutely! .hsplus is a full programming language - you can build entire backends with it.

**Backend with .hsplus:**

```hsplus
// server.hsplus
import { Server, Router, json } from "@holoscript/server";
import { Database } from "@holoscript/db";
import { auth } from "./middleware/auth";

const db = new Database("postgresql://localhost/hololand");
const app = new Server({ port: 3001 });
const router = new Router();

// REST API for worlds
router.get("/api/worlds", async (req, res) => {
  const worlds = await db.query("SELECT * FROM worlds WHERE public = true");
  res.json(worlds);
});

router.post("/api/worlds", auth, async (req, res) => {
  const { name, template } = req.body;
  const world = await db.insert("worlds", {
    name,
    template,
    owner_id: req.user.id,
    created_at: new Date()
  });
  res.json(world);
});

// WebSocket for real-time multiplayer
app.ws("/game/:worldId", async (ws, req) => {
  const worldId = req.params.worldId;
  const room = GameRooms.get(worldId);

  ws.on("message", (data) => {
    const msg = JSON.parse(data);

    switch (msg.type) {
      case "move":
        room.broadcast({
          type: "player_moved",
          playerId: ws.playerId,
          position: msg.position
        });
        break;

      case "action":
        room.handleAction(ws.playerId, msg.action);
        break;
    }
  });

  ws.on("close", () => {
    room.removePlayer(ws.playerId);
  });
});

app.use(router);
app.listen();
console.log("Server running on port 3001");
```

