**More backend examples:**

```hsplus
// auth.hsplus - Authentication
import { jwt, hash } from "@holoscript/crypto";

export async function login(email: string, password: string): Promise<Token> {
  const user = await db.findOne("users", { email });
  if (!user) throw new Error("User not found");

  const valid = await hash.verify(password, user.password_hash);
  if (!valid) throw new Error("Invalid password");

  return jwt.sign({ userId: user.id }, process.env.JWT_SECRET, {
    expiresIn: "7d"
  });
}
```

```hsplus
// matchmaking.hsplus - Game server logic
export system Matchmaking {
  private queues: Map<string, Player[]> = new Map();

  addToQueue(player: Player, mode: string): void {
    const queue = this.queues.get(mode) ?? [];
    queue.push(player);
    this.queues.set(mode, queue);

    this.tryMatch(mode);
  }

  private tryMatch(mode: string): void {
    const queue = this.queues.get(mode)!;
    const required = this.getRequiredPlayers(mode);

    if (queue.length >= required) {
      const players = queue.splice(0, required);
      this.createMatch(players, mode);
    }
  }

  private async createMatch(players: Player[], mode: string): Promise<void> {
    const match = await db.insert("matches", {
      mode,
      players: players.map(p => p.id),
      status: "starting"
    });

    // Notify all players
    for (const player of players) {
      player.ws.send(JSON.stringify({
        type: "match_found",
        matchId: match.id
      }));
    }
  }
}
```

**.holo can even define backend structure:**

```holo
// api-schema.holo - Define your API visually
composition "GameAPI" {

  endpoint "/api/worlds" {
    GET: { returns: "World[]", auth: false }
    POST: { returns: "World", auth: true, body: "CreateWorldRequest" }
  }

  endpoint "/api/worlds/:id" {
    GET: { returns: "World", auth: false }
    PUT: { returns: "World", auth: true, requires: "owner" }
    DELETE: { returns: "void", auth: true, requires: "owner" }
  }

  websocket "/game/:worldId" {
    messages: {
      "move": { position: "Vec3" }
      "action": { type: "string", target: "string" }
      "chat": { message: "string" }
    }
    broadcasts: {
      "player_moved": { playerId: "string", position: "Vec3" }
      "player_action": { playerId: "string", action: "Action" }
    }
  }
}
```

